import { useEffect, useState, useCallback } from "react";
import { Link } from "react-router-dom";
import { FaPlane, FaPlus, FaSearch, FaMapMarkerAlt, FaCalendarAlt, FaDollarSign, FaHeart, FaRegHeart } from "react-icons/fa";
import toast from "react-hot-toast";

import { getTrips, toggleWishlist, getWishlistedTrips } from "../../services/tripService";
import { useAuth } from "../../context/AuthContext";
import styles from "./Trips.module.css";

const Trips = () => {
    const { user } = useAuth();
    const [activeTab, setActiveTab] = useState("my-trips"); // "my-trips", "explore", "wishlist"
    const [trips, setTrips] = useState([]);
    const [loading, setLoading] = useState(true);

    // Filters & Pagination State
    const [search, setSearch] = useState("");
    const [status, setStatus] = useState("");
    const [page, setPage] = useState(1);
    const [pagination, setPagination] = useState({ page: 1, pages: 1 });

    const fetchTripsData = useCallback(async () => {
        setLoading(true);
        try {
            if (activeTab === "wishlist") {
                const res = await getWishlistedTrips();
                setTrips(res.trips);
                setPagination({ page: 1, pages: 1 });
            } else {
                const isPublic = activeTab === "explore";
                const params = {
                    search,
                    page,
                    limit: 6,
                    isPublic,
                };
                if (status) params.status = status;

                const res = await getTrips(params);
                setTrips(res.trips);
                setPagination(res.pagination);
            }
        } catch (error) {
            toast.error(error.message || "Failed to fetch trips.");
        } finally {
            setLoading(false);
        }
    }, [activeTab, search, status, page]);

    useEffect(() => {
        fetchTripsData();
    }, [fetchTripsData]);

    const handleTabChange = (tabName) => {
        setActiveTab(tabName);
        setPage(1);
        setSearch("");
        setStatus("");
    };

    const handleWishlistToggle = async (tripId, e) => {
        e.preventDefault();
        e.stopPropagation();
        try {
            const res = await toggleWishlist(tripId);
            toast.success(res.message);
            // Refresh list
            fetchTripsData();
        } catch (error) {
            toast.error(error.message);
        }
    };

    return (
        <div className={styles.container}>
            <div className={styles.header}>
                <div>
                    <h1>Travel Registry</h1>
                    <p style={{ color: "var(--subText)" }}>
                        {activeTab === "my-trips" && "Track and manage your upcoming and past itineraries."}
                        {activeTab === "explore" && "Discover and get inspired by other travelers' public journeys."}
                        {activeTab === "wishlist" && "Keep track of destinations you plan to copy or visit later."}
                    </p>
                </div>
                <Link to="/create-trip" className={styles.planBtn}>
                    <FaPlus /> Plan Adventure
                </Link>
            </div>

            {/* Navigation tabs */}
            <div className={styles.tabs}>
                <button
                    className={`${styles.tab} ${activeTab === "my-trips" ? styles.activeTab : ""}`}
                    onClick={() => handleTabChange("my-trips")}
                >
                    My Trips
                </button>
                <button
                    className={`${styles.tab} ${activeTab === "explore" ? styles.activeTab : ""}`}
                    onClick={() => handleTabChange("explore")}
                >
                    Explore Public Trips
                </button>
                <button
                    className={`${styles.tab} ${activeTab === "wishlist" ? styles.activeTab : ""}`}
                    onClick={() => handleTabChange("wishlist")}
                >
                    My Wishlist
                </button>
            </div>

            {/* Filter controls (Only for trips and explore) */}
            {activeTab !== "wishlist" && (
                <div className={styles.filterBar}>
                    <div className={styles.filterGroup} style={{ gridColumn: "span 1" }}>
                        <label>Search</label>
                        <div style={{ position: "relative" }}>
                            <input
                                type="text"
                                placeholder="Search country, city, destination..."
                                value={search}
                                onChange={(e) => {
                                    setSearch(e.target.value);
                                    setPage(1);
                                }}
                                style={{ paddingLeft: "35px", width: "100%" }}
                            />
                            <FaSearch style={{ position: "absolute", left: "12px", top: "14px", color: "var(--subText)" }} />
                        </div>
                    </div>

                    <div className={styles.filterGroup}>
                        <label>Status</label>
                        <select
                            value={status}
                            onChange={(e) => {
                                setStatus(e.target.value);
                                setPage(1);
                            }}
                        >
                            <option value="">All Statuses</option>
                            <option value="Upcoming">Upcoming</option>
                            <option value="Completed">Completed</option>
                            <option value="Cancelled">Cancelled</option>
                        </select>
                    </div>
                </div>
            )}

            {/* Main trips view grid */}
            {loading ? (
                <div className="global-loader-container" style={{ minHeight: "200px" }}>
                    <div className="global-loader"></div>
                </div>
            ) : trips.length > 0 ? (
                <>
                    <div className={styles.grid}>
                        {trips.map((trip) => {
                            const isOwner = String(trip.user._id || trip.user) === user?.id;
                            const isLiked = trip.wishlistedBy?.includes(user?.id);

                            return (
                                <div className={styles.tripCard} key={trip._id}>
                                    <div className={styles.cardHeader}>
                                        <img
                                            src={trip.tripImage || "https://images.unsplash.com/photo-1507525428034-b723cf961d3e?w=800"}
                                            alt={trip.destination}
                                            className={styles.cardImage}
                                        />
                                        <span className={`${styles.cardBadge} ${styles[`badge${trip.status}`]}`}>
                                            {trip.status}
                                        </span>

                                        {/* Wishlist toggle button */}
                                        {!isOwner && (
                                            <button
                                                onClick={(e) => handleWishlistToggle(trip._id, e)}
                                                className={styles.wishlistBtn}
                                                title={isLiked ? "Remove from Wishlist" : "Add to Wishlist"}
                                            >
                                                {isLiked ? <FaHeart /> : <FaRegHeart />}
                                            </button>
                                        )}
                                    </div>
                                    <div className={styles.cardBody}>
                                        <h3>{trip.destination}</h3>
                                        <div className={styles.location}>
                                            <FaMapMarkerAlt /> {trip.city}, {trip.country}
                                        </div>

                                        <div className={styles.metaGrid}>
                                            <div className={styles.metaItem}>
                                                <span className={styles.metaLabel}>Budget</span>
                                                <span className={styles.metaVal}>${trip.budget.toLocaleString()}</span>
                                            </div>
                                            <div className={styles.metaItem}>
                                                <span className={styles.metaLabel}>Travelers</span>
                                                <span className={styles.metaVal}>{trip.travelers} {trip.travelers > 1 ? "people" : "person"}</span>
                                            </div>
                                            <div className={styles.metaItem} style={{ gridColumn: "span 2" }}>
                                                <span className={styles.metaLabel}>Dates</span>
                                                <span className={styles.metaVal}>
                                                    {new Date(trip.startDate).toLocaleDateString()} - {new Date(trip.endDate).toLocaleDateString()}
                                                </span>
                                            </div>
                                        </div>

                                        <Link to={`/trips/${trip._id}`} className={styles.viewBtn}>
                                            View Details
                                        </Link>
                                    </div>
                                </div>
                            );
                        })}
                    </div>

                    {/* Pagination controller */}
                    {pagination.pages > 1 && (
                        <div className={styles.pagination}>
                            <button
                                disabled={page === 1}
                                onClick={() => setPage(page - 1)}
                                className={styles.pageBtn}
                            >
                                Previous
                            </button>
                            {Array.from({ length: pagination.pages }, (_, i) => i + 1).map((pNum) => (
                                <button
                                    key={pNum}
                                    className={`${styles.pageBtn} ${page === pNum ? styles.activePage : ""}`}
                                    onClick={() => setPage(pNum)}
                                >
                                    {pNum}
                                </button>
                            ))}
                            <button
                                disabled={page === pagination.pages}
                                onClick={() => setPage(page + 1)}
                                className={styles.pageBtn}
                            >
                                Next
                            </button>
                        </div>
                    )}
                </>
            ) : (
                <div style={{ textAlign: "center", padding: "60px 20px", background: "var(--card)", border: "1px solid var(--border)", borderRadius: "var(--radius)" }}>
                    <FaPlane size={48} style={{ color: "var(--subText)", marginBottom: "20px" }} />
                    <h3>No trips found</h3>
                    <p style={{ color: "var(--subText)", margin: "10px 0 20px" }}>
                        We couldn't find any trips. Try resetting filters or creating a new trip log.
                    </p>
                </div>
            )}
        </div>
    );
};

export default Trips;
